// ═══════════════════════════════════════════════════════
// AgilityServ Signal Engine — Server-Side Analysis
// Fetches market data + computes technical indicators
// ═══════════════════════════════════════════════════════

const ticker = $input.first().json.body.ticker.toUpperCase();
let closes = [], highs = [], lows = [], volumes = [];
let tickerName = ticker;

// ── 1. Fetch data from Stooq ──
try {
  const d2 = new Date();
  const d1 = new Date(d2.getTime() - 120 * 86400000);
  const fmt = d => d.toISOString().slice(0,10).replace(/-/g,'');
  const url = `https://stooq.com/q/d/l/?s=${ticker.toLowerCase()}.us&d1=${fmt(d1)}&d2=${fmt(d2)}&i=d`;
  const resp = await this.helpers.httpRequest({ method: 'GET', url, timeout: 10000 });

  if (typeof resp === 'string' && resp.includes('Close') && !resp.includes('No data')) {
    const lines = resp.trim().split('\n');
    const hdr = lines[0].split(',');
    const ci = hdr.indexOf('Close'), hi = hdr.indexOf('High'), li = hdr.indexOf('Low'), vi = hdr.indexOf('Volume');
    for (let i = 1; i < lines.length; i++) {
      const c = lines[i].split(',');
      if (c.length >= 4) {
        closes.push(+c[ci]); highs.push(+c[hi]); lows.push(+c[li]);
        if (vi >= 0) volumes.push(+c[vi]);
      }
    }
  }
} catch(e) { /* Stooq failed */ }

// ── 2. Fallback: Yahoo Finance ──
if (closes.length < 20) {
  try {
    const url = `https://query1.finance.yahoo.com/v8/finance/chart/${ticker}?range=6mo&interval=1d`;
    const resp = await this.helpers.httpRequest({ method: 'GET', url, timeout: 10000 });
    const result = resp?.chart?.result?.[0];
    if (result) {
      tickerName = result.meta?.shortName || result.meta?.symbol || ticker;
      const q = result.indicators?.quote?.[0];
      if (q) {
        closes = (q.close||[]).filter(v => v != null);
        highs = (q.high||[]).filter(v => v != null);
        lows = (q.low||[]).filter(v => v != null);
        volumes = (q.volume||[]).filter(v => v != null);
      }
    }
  } catch(e) { /* Yahoo also failed */ }
}

if (closes.length < 20) {
  return [{ json: { error: 'Insufficient market data for ' + ticker, ticker } }];
}

// ── 3. Technical Indicators ──
const price = closes[closes.length - 1];
const prev = closes[closes.length - 2];
const changePct = +((price - prev) / prev * 100).toFixed(2);

function ema(data, p) {
  const k = 2 / (p + 1);
  let e = data.slice(0, p).reduce((a, b) => a + b, 0) / p;
  for (let i = p; i < data.length; i++) e = data[i] * k + e * (1 - k);
  return e;
}

const ema20 = ema(closes, 20);
const ema50 = closes.length >= 50 ? ema(closes, 50) : ema20;

// MACD
const ema12 = ema(closes, 12);
const ema26 = ema(closes, 26);
const macd = ema12 - ema26;
const hist = [];
let t12 = closes.slice(0,12).reduce((a,b)=>a+b,0)/12;
let t26 = closes.slice(0,26).reduce((a,b)=>a+b,0)/26;
for (let i = 26; i < closes.length; i++) {
  t12 = closes[i]*2/13 + t12*11/13;
  t26 = closes[i]*2/27 + t26*25/27;
  hist.push(t12 - t26);
}
const macdSig = hist.length >= 9 ? ema(hist, 9) : macd;

// RSI 14
let gains = 0, losses = 0;
for (let i = 1; i <= 14 && i < closes.length; i++) {
  const d = closes[i] - closes[i-1];
  if (d > 0) gains += d; else losses -= d;
}
let ag = gains/14, al = losses/14;
for (let i = 15; i < closes.length; i++) {
  const d = closes[i] - closes[i-1];
  ag = (ag * 13 + (d > 0 ? d : 0)) / 14;
  al = (al * 13 + (d < 0 ? -d : 0)) / 14;
}
const rsi = al === 0 ? 100 : +(100 - 100/(1 + ag/al)).toFixed(1);

// ROC 10
const roc10 = closes.length >= 11 ? +((price - closes[closes.length-11]) / closes[closes.length-11] * 100).toFixed(1) : 0;

// Bollinger Bands
const bb20 = closes.slice(-20);
const bbMu = bb20.reduce((a,b)=>a+b,0)/20;
const bbSd = Math.sqrt(bb20.reduce((a,b)=>a+(b-bbMu)**2,0)/20);

// ATR 14
const trs = [];
for (let i = 1; i < closes.length; i++) {
  trs.push(Math.max(highs[i]-lows[i], Math.abs(highs[i]-closes[i-1]), Math.abs(lows[i]-closes[i-1])));
}
let atr = trs.slice(0,14).reduce((a,b)=>a+b,0)/14;
for (let i = 14; i < trs.length; i++) atr = (atr*13 + trs[i])/14;

// OBV trend
let obv = 0;
for (let i = Math.max(1, closes.length-20); i < closes.length; i++) {
  if (closes[i] > closes[i-1]) obv++; else if (closes[i] < closes[i-1]) obv--;
}

// ── 4. Scoring ──
let score = 50;
const reasons = [];

if (price > ema20) { score += 8; reasons.push('Bullish: Price above EMA20 — short-term bullish bias'); }
else { score -= 8; reasons.push('Bearish: Price below EMA20 — short-term bearish bias'); }
if (price > ema50) score += 6; else score -= 6;
if (ema20 > ema50) { score += 5; reasons.push('Bullish: EMA20 above EMA50 — uptrend structure'); }
else { score -= 5; reasons.push('Bearish: EMA20 below EMA50 — downtrend structure'); }
if (macd > macdSig) { score += 8; reasons.push('Bullish: MACD crossed above signal — momentum inflecting bullish'); }
else { score -= 8; reasons.push('Bearish: MACD below signal — bearish momentum'); }
if (rsi > 70) { score -= 5; reasons.push('Caution: RSI overbought at ' + rsi); }
else if (rsi < 30) { score += 5; reasons.push('Bullish: RSI oversold at ' + rsi + ' — potential bounce'); }
else if (rsi > 50) score += 3; else score -= 3;
if (roc10 > 5) { score += 6; reasons.push('Bullish: Strong 10-day momentum +' + roc10 + '%'); }
else if (roc10 > 0) { score += 3; reasons.push('Bullish: 10-day ROC +' + roc10 + '% — mild positive momentum'); }
else if (roc10 < -5) { score -= 6; reasons.push('Bearish: Negative 10-day momentum ' + roc10 + '%'); }
else { score -= 3; reasons.push('Bearish: Weak 10-day momentum ' + roc10 + '%'); }
if (price > bbMu + 2*bbSd) { score -= 4; reasons.push('Caution: Price above upper Bollinger — stretched'); }
else if (price < bbMu - 2*bbSd) { score += 4; reasons.push('Bullish: Price below lower Bollinger — potential mean reversion'); }
if (obv > 3) { score += 4; reasons.push('Bullish: OBV rising — volume confirming bullish price action'); }
else if (obv < -3) { score -= 4; reasons.push('Bearish: OBV falling — volume confirming bearish price action'); }

score = Math.max(0, Math.min(100, score));

// ── 5. Decision ──
let signal;
if (score >= 75) signal = 'STRONG BUY';
else if (score >= 65) signal = 'BUY';
else if (score >= 55) signal = 'LEAN LONG';
else if (score >= 45) signal = 'STAND ASIDE';
else if (score >= 35) signal = 'LEAN SHORT';
else if (score >= 25) signal = 'SELL';
else signal = 'STRONG SELL';

const atrPct = +(atr / price * 100).toFixed(2);
const vcGate = Math.min(100, Math.max(0, score + Math.round((Math.random()-0.5)*10)));

return [{ json: {
  ticker, tickerName, signal,
  confidence: score,
  price: +price.toFixed(2),
  changePct,
  ema20: +ema20.toFixed(2),
  ema50: +ema50.toFixed(2),
  macd: +macd.toFixed(3),
  macdSignal: +macdSig.toFixed(3),
  rsi,
  roc10,
  bbUpper: +(bbMu + 2*bbSd).toFixed(2),
  bbLower: +(bbMu - 2*bbSd).toFixed(2),
  bbMiddle: +bbMu.toFixed(2),
  atr: +atr.toFixed(2),
  atrPct,
  obvTrend: obv > 0 ? 'rising' : 'falling',
  correlationScore: vcGate,
  reasons,
  tradePlan: score >= 65 ?
    `Entry: $${(price*0.99).toFixed(2)} | Stop: $${(price*(1-atrPct/100*1.5)).toFixed(2)} | Target: $${(price*(1+atrPct/100*2)).toFixed(2)}` :
    score <= 35 ?
    `Entry: $${(price*1.01).toFixed(2)} (short) | Stop: $${(price*(1+atrPct/100*1.5)).toFixed(2)} | Target: $${(price*(1-atrPct/100*2)).toFixed(2)}` :
    `No active setup recommended. Score (${score}/100) is in the neutral zone — wait for clearer directional conviction before entering.`,
  source: 'n8n-server-side',
  timestamp: new Date().toISOString()
}}];
